<?php require '../config.php'; require_admin(); require '_nav.php'; $rows=$pdo->query('SELECT u.*, COUNT(h.id) hosting_count FROM users u LEFT JOIN hosting_accounts h ON h.user_id=u.id GROUP BY u.id ORDER BY u.id DESC')->fetchAll(); ?>
<!doctype html><html><head><title>Customers</title><link rel="stylesheet" href="/style.css"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><div class="dash"><?php admin_nav(); ?><div class="main"><h1>Customers</h1><table class="table"><tr><th>Name</th><th>Email</th><th>Hosting Accounts</th><th>Joined</th></tr><?php foreach($rows as $r):?><tr><td><?=h($r['name'])?></td><td><?=h($r['email'])?></td><td><?=h($r['hosting_count'])?></td><td><?=h($r['created_at'])?></td></tr><?php endforeach;?></table></div></div></body></html>
